//! `--scope` — which side(s) of a dual workspace a command
//! operates on. See [options_flags](README.md) for shared
//! architecture.
//!
//! - `Side` is the role enum — `Work` or `Bot`; the CLI
//!   keywords that name them are `code` and `bot`.
//! - `Scope` is a newtype over `Vec<Side>` — the parsed role
//!   set (`code`, `bot`, `code,bot`, `bot,code`).
//! - Path-based single-repo operation lives on `-R/--repo`,
//!   not in `--scope`; `Scope` carries role information only.

use clap::ValueEnum;

/// One side of a dual-repo workspace.
///
/// - `Work` — the primary work repo.
/// - `Bot` — the bot repo (typically at `.claude/`).
#[derive(Copy, Clone, Debug, PartialEq, Eq, ValueEnum)]
pub enum Side {
    Work,
    Bot,
}

/// Parsed `--scope` value — the requested role set of a
/// dual-repo workspace.
///
/// Newtype over `Vec<Side>`; the vector preserves the order the
/// keywords were given in (`code,bot` vs `bot,code`).
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct Scope(pub Vec<Side>);

/// Parse a `--scope` value string.
///
/// Accepts exactly the four role-keyword forms — `code`, `bot`,
/// `code,bot`, `bot,code` — preserving order. Anything else (an
/// empty string, a bare name, duplicate or out-of-set
/// combinations, a path) is an error: path-based single-repo
/// operation uses `-R/--repo`, not `--scope`.
pub fn parse_scope(s: &str) -> Result<Scope, String> {
    match s {
        "code" => Ok(Scope(vec![Side::Work])),
        "bot" => Ok(Scope(vec![Side::Bot])),
        "code,bot" => Ok(Scope(vec![Side::Work, Side::Bot])),
        "bot,code" => Ok(Scope(vec![Side::Bot, Side::Work])),
        "" => Err("--scope: value is empty".into()),
        other => Err(format!(
            "--scope: '{other}' is not a recognized form. \
             Expected one of `code`, `bot`, `code,bot`, `bot,code`. \
             For single-repo operation by path, use `-R/--repo`."
        )),
    }
}

impl Scope {
    /// True when the role set includes the work side.
    pub fn has_work(&self) -> bool {
        self.0.contains(&Side::Work)
    }

    /// True when the role set includes the bot side.
    pub fn has_bot(&self) -> bool {
        self.0.contains(&Side::Bot)
    }

    /// Exactly the work side — a single-side dual-repo op.
    pub fn is_work_only(&self) -> bool {
        self.has_work() && !self.has_bot()
    }

    /// Exactly the bot side — a single-side dual-repo op.
    #[allow(dead_code)]
    pub fn is_bot_only(&self) -> bool {
        !self.has_work() && self.has_bot()
    }

    /// Both sides — a full dual-repo op.
    pub fn is_both(&self) -> bool {
        self.has_work() && self.has_bot()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn work_only() {
        let s = Scope(vec![Side::Work]);
        assert!(s.is_work_only());
        assert!(!s.is_bot_only());
        assert!(!s.is_both());
    }

    #[test]
    fn bot_only() {
        let s = Scope(vec![Side::Bot]);
        assert!(!s.is_work_only());
        assert!(s.is_bot_only());
        assert!(!s.is_both());
    }

    #[test]
    fn both_work_then_bot() {
        let s = Scope(vec![Side::Work, Side::Bot]);
        assert!(!s.is_work_only());
        assert!(!s.is_bot_only());
        assert!(s.is_both());
    }

    #[test]
    fn both_bot_then_work() {
        // Order doesn't matter — contains-based checks.
        let s = Scope(vec![Side::Bot, Side::Work]);
        assert!(s.is_both());
    }

    #[test]
    fn empty_roles() {
        // Empty side list isn't a state anything constructs (the
        // parser rejects empty input), but the helpers still need
        // to be well-defined on it.
        let s = Scope(vec![]);
        assert!(!s.is_work_only());
        assert!(!s.is_bot_only());
        assert!(!s.is_both());
    }

    #[test]
    fn parse_keyword_code() {
        assert_eq!(parse_scope("code").unwrap(), Scope(vec![Side::Work]));
    }

    #[test]
    fn parse_keyword_bot() {
        assert_eq!(parse_scope("bot").unwrap(), Scope(vec![Side::Bot]));
    }

    #[test]
    fn parse_keyword_code_bot_preserves_order() {
        assert_eq!(
            parse_scope("code,bot").unwrap(),
            Scope(vec![Side::Work, Side::Bot])
        );
    }

    #[test]
    fn parse_keyword_bot_code_preserves_order() {
        assert_eq!(
            parse_scope("bot,code").unwrap(),
            Scope(vec![Side::Bot, Side::Work])
        );
    }

    #[test]
    fn parse_bare_name_errors() {
        let err = parse_scope("foo").unwrap_err();
        assert!(err.contains("'foo'"), "got: {err}");
    }

    #[test]
    fn parse_empty_errors() {
        let err = parse_scope("").unwrap_err();
        assert!(err.contains("empty"), "got: {err}");
    }

    #[test]
    fn parse_path_form_errors() {
        // Path forms are no longer a `--scope` value — `-R/--repo`
        // handles single-repo operation. The error points there.
        let err = parse_scope("./foo").unwrap_err();
        assert!(err.contains("-R/--repo"), "got: {err}");
    }

    #[test]
    fn parse_unknown_keyword_combo_errors() {
        // Duplicates and out-of-set combos are rejected; only the
        // exact four keyword forms are accepted.
        assert!(parse_scope("code,code").is_err());
        assert!(parse_scope("code,bot,code").is_err());
        assert!(parse_scope("bot,bot").is_err());
    }
}

//! `CommonArgs` — the shared arg set for the read-only commit-query
//! subcommands (`chid` / `desc` / `list` / `show`): a `REVISION` /
//! `COMMITS` positional pair, `-r`/`--revision`, `-R`/`--repo`,
//! `-s`/`--scope`, `-n`/`--commits`, and the `-l`/`-L` inter-repo
//! label pair.
//!
//! A "bundle" in the inline-fields sense (cf. `provision_bundle`'s
//! flatten-of-leaves form): the fields aren't extracted into per-flag
//! leaves because none of them is reused outside these four — if one
//! ever is (e.g. a future command wants just `--revision`), extract
//! that field into a leaf and `#[command(flatten)]` it here. Consumers
//! flatten this and add their own extra `#[arg]` fields (`list`'s
//! `-w`/`--width`, `show`'s `-f`/`--files`). See
//! [options_flags](README.md) for shared architecture.

use std::path::PathBuf;

use clap::Args;

use super::scope::{Scope, parse_scope};

/// Shared CLI args for the read-only commit-query subcommands —
/// see [Bundle](README.md#architecture).
///
/// - `pos_rev` / `pos_count` — the `REVISION` / `COMMITS` positionals
///   (`common::resolve_spec` reconciles them with `-r` / `-n`).
/// - `revision` — `-r` / `--revision` (default `@`); `..` notation is
///   parsed downstream by `common::parse_dot_rev`.
/// - `repo` / `scope` — `-R PATH` overrides the workspace root, `-s
///   code|bot|code,bot` selects sides; they compose
///   (`common::resolve_repos`). Defaults preserve today's behavior:
///   no flag → `[.]`, `-R foo` alone → `[foo]`. `-s` alone resolves
///   against `find_workspace_root()`; `-R + -s` resolves against the
///   `-R` path. `-s` is keyword-only (`code|bot|code,bot|bot,code`);
///   path-based single-repo operation routes through `-R`.
/// - `limit` — `-n` / `--commits`, caps the output.
/// - `label` / `no_label` — `-l` / `--label` (default `===`) and
///   `-L` / `--no-label`; `common::resolve_header` combines them.
#[derive(Args, Debug)]
pub struct CommonArgs {
    /// Revision (with optional .. notation)
    #[arg(value_name = "REVISION")]
    pub pos_rev: Option<String>,

    /// Number of commits to show (per open side)
    #[arg(value_name = "COMMITS")]
    pub pos_count: Option<usize>,

    /// Revision to query
    #[arg(short, long, default_value = "@")]
    pub revision: String,

    /// Workspace root or single jj repo path [default: .]
    #[arg(short = 'R', long = "repo", value_name = "PATH")]
    pub repo: Option<PathBuf>,

    /// Side(s) to query; composes with --repo as workspace root
    #[arg(
        short = 's',
        long = "scope",
        value_name = "code|bot|code,bot",
        value_parser = parse_scope
    )]
    pub scope: Option<Scope>,

    /// Number of commits to show
    #[arg(short = 'n', long = "commits", value_name = "COMMITS")]
    pub limit: Option<usize>,

    /// Custom label decoration between repos
    #[arg(
        short = 'l',
        long = "label",
        value_name = "TEXT",
        allow_hyphen_values = true,
        default_value = "==="
    )]
    pub label: String,

    /// Suppress label between repos
    #[arg(short = 'L', long = "no-label")]
    pub no_label: bool,
}

impl CommonArgs {
    /// Resolve `-R` + `-s` into the concrete repo paths to iterate
    /// (delegates to [`crate::common::resolve_repos`]).
    ///
    /// Bundles the `.as_deref()` / `.as_ref()` conversion ceremony
    /// (`Option<PathBuf>` → `Option<&Path>`,
    /// `Option<Scope>` → `Option<&Scope>`) into one well-named place
    /// so the four subcommand bodies stay clean. See
    /// [`../../notes/rust-idioms.md`](../../notes/rust-idioms.md)
    /// for why the two fields need different conversion methods
    /// (`PathBuf: Deref<Target = Path>`; `Scope` is a plain enum).
    pub fn resolve_repos(&self) -> Result<Vec<std::path::PathBuf>, Box<dyn std::error::Error>> {
        crate::common::resolve_repos(self.repo.as_deref(), self.scope.as_ref())
    }
}

impl super::OptionFlagBundle for CommonArgs {}

