use std::collections::HashMap;
use std::sync::Arc;

use jj_lib::object_id::ObjectId;
use jj_lib::repo::{ReadonlyRepo, Repo};
use jj_lib::workspace::Workspace;

use crate::common;
use crate::toml_simple;

pub const DEFAULT_ID_LEN: usize = 12;
pub const VC_CONFIG_FILE: &str = ".vc-config.toml";

/// Read the other repo path from a repo's `.vc-config.toml`.
///
/// Returns the `workspace.other-repo` value, which is the relative path
/// to the counterpart repo from the repo's directory.
pub fn other_repo_from_config(
    config: &HashMap<String, String>,
) -> Result<String, Box<dyn std::error::Error>> {
    toml_simple::toml_get(config, "workspace.other-repo")
        .cloned()
        .ok_or_else(|| "missing workspace.other-repo in .vc-config.toml".into())
}

/// Derive the ochid prefix from a repo's `.vc-config.toml`.
///
/// The `workspace.path` value is the repo's path relative to the workspace
/// root, which is exactly the ochid prefix (with a trailing `/` when the
/// path isn't just `/`).
pub fn ochid_prefix_from_config(
    config: &HashMap<String, String>,
) -> Result<String, Box<dyn std::error::Error>> {
    let ws_path = toml_simple::toml_get(config, "workspace.path")
        .ok_or("missing workspace.path in .vc-config.toml")?;
    let trimmed = ws_path.trim_end_matches('/');
    if trimmed.is_empty() {
        Ok("/".to_string())
    } else {
        Ok(format!("{trimmed}/"))
    }
}

/// Problems found with an ochid trailer, with details for reporting.
#[derive(Debug)]
pub struct OchidIssues {
    /// None if prefix is correct, Some((actual_prefix, expected_prefix)) if wrong.
    pub wrong_prefix: Option<(String, String)>,
    /// None if length is correct, Some((actual_len, expected_len)) if wrong.
    pub wrong_length: Option<(usize, usize)>,
    /// true if the bare ID does not resolve in the other repo.
    pub not_found: bool,
    /// The bare ID extracted from the ochid value.
    pub bare_id: String,
}

impl OchidIssues {
    pub fn any(&self) -> bool {
        self.wrong_prefix.is_some() || self.wrong_length.is_some() || self.not_found
    }

