122	/// Parse the `--use-template` value into `(work, bot)` template paths.
123	///
124	/// Format: `WORK[,BOT]`. If `BOT` is omitted, the default is the sibling
125	/// directory whose name is `<WORK-basename>.claude` (via
126	/// `Path::with_file_name`, so a trailing slash on `CODE` does not produce
127	/// a different result).
128	pub(crate) fn parse_use_template(
129	    s: &str,
130	) -> Result<(PathBuf, PathBuf), Box<dyn std::error::Error>> {
131	    let mut parts = s.splitn(2, ',');
132	    let work_raw = parts.next().unwrap_or(""); // OK: splitn always yields at least one element
133	    let bot_raw = parts.next();
134	    let work_trim = work_raw.trim();
135	    if work_trim.is_empty() {
136	        return Err("--use-template: work template path is empty".into());
137	    }
138	    let work = PathBuf::from(work_trim);
139	    let bot = match bot_raw.map(str::trim) {
140	        Some(b) if !b.is_empty() => PathBuf::from(b),
141	        _ => {
142	            let file_name = work.file_name().ok_or_else(|| {
143	                format!(
144	                    "--use-template: cannot derive default bot path from '{}' (no file name component)",
145	                    work.display()
146	                )
147	            })?;
148	            let new_name = format!("{}.claude", file_name.to_string_lossy());
149	            work.with_file_name(new_name)
150	        }
151	    };
152	    Ok((work, bot))
153	}
