116	    commit: &jj_lib::commit::Commit,
117	    other_workspace: &Workspace,
118	    other_repo: &Arc<ReadonlyRepo>,
119	) -> Result<TitleMatch, Box<dyn std::error::Error>> {
120	    let title = commit.description().lines().next().unwrap_or(""); // OK: obvious
121	    if title.is_empty() {
122	        return Ok(TitleMatch::NoTitle);
123	    }
124	
125	    let all_ids = common::resolve_revset(other_workspace, other_repo, "all()")?;
126	    let root_id = other_repo.store().root_commit_id().clone();
127	
128	    let mut matches = Vec::new();
129	    for cid in &all_ids {
130	        if *cid == root_id {
131	            continue;
132	        }
133	        let other_commit = other_repo.store().get_commit(cid)?;
134	        let other_title = other_commit.description().lines().next().unwrap_or(""); // OK: obvious
135	        if other_title == title {
136	            let full_hex =
137	                jj_lib::hex_util::encode_reverse_hex(other_commit.change_id().as_bytes());
138	            matches.push(full_hex);
